from manim import *

class BackpropGradientFlowStory(Scene):
    def construct(self):
        title = Text('Backpropagation Sends Error Information Back Through The Network', font_size=25).to_edge(UP)
        layers = VGroup(*[
            RoundedRectangle(corner_radius=0.1, width=1.3, height=1.0, color=BLUE_D if i < 3 else TEAL_D, fill_opacity=0.15)
            for i in range(4)
        ]).arrange(RIGHT, buff=0.8).shift(UP * 0.5)
        labels = VGroup(*[
            Text(label, font_size=18, color=WHITE).move_to(layer)
            for label, layer in zip(['input', 'hidden 1', 'hidden 2', 'output'], layers)
        ])
        forward_arrows = VGroup(*[
            Arrow(layers[i].get_right(), layers[i + 1].get_left(), buff=0.08, color=GRAY_B)
            for i in range(3)
        ])
        backward_arrows = VGroup(
            Arrow(layers[3].get_left(), layers[2].get_right(), buff=0.08, color=ORANGE, stroke_width=6),
            Arrow(layers[2].get_left(), layers[1].get_right(), buff=0.08, color=ORANGE, stroke_width=4),
            Arrow(layers[1].get_left(), layers[0].get_right(), buff=0.08, color=ORANGE, stroke_width=3),
        )
        bars = VGroup(*[
            Rectangle(width=0.42, height=h, color=ORANGE, fill_color=ORANGE, fill_opacity=0.45)
            for h in [0.45, 0.75, 1.15, 1.5]
        ]).arrange(RIGHT, buff=1.68, aligned_edge=DOWN).move_to(DOWN * 2.15)
        bar_labels = VGroup(*[
            Text(text, font_size=16, color=ORANGE).next_to(bar, DOWN, buff=0.1)
            for text, bar in zip(['tiny', 'small', 'medium', 'large'], bars)
        ])
        magnitude_label = Text('gradient magnitude', font_size=18, color=ORANGE).next_to(bars, UP, buff=0.16)
        caption = Text('The loss is measured at the output, then gradients flow backward so each earlier layer knows how to update.', font_size=21, color=WHITE).to_edge(DOWN)
        caption_group = VGroup(BackgroundRectangle(caption, fill_opacity=0.88, buff=0.14), caption)

        self.play(FadeIn(title), FadeIn(layers), FadeIn(labels), run_time=2.0)
        self.play(LaggedStart(*[GrowArrow(arrow) for arrow in forward_arrows], lag_ratio=0.16), run_time=1.6)
        self.play(LaggedStart(*[GrowArrow(arrow) for arrow in backward_arrows], lag_ratio=0.2), run_time=2.0)
        self.play(LaggedStart(*[GrowFromEdge(bar, DOWN) for bar in bars], lag_ratio=0.14), FadeIn(bar_labels), FadeIn(magnitude_label), run_time=2.1)
        self.play(FadeIn(caption_group), Indicate(backward_arrows, color=YELLOW_A), run_time=1.5)
        self.wait(1)
